function wpbp_database_006(): array { global $wpdb; require_once ABSPATH . 'wp-admin/includes/upgrade.php'; $table = $wpdb->prefix . 'wpbp_database_006'; $charset_collate = $wpdb->get_charset_collate(); $sql = "CREATE TABLE {$table} (
id bigint(20) unsigned NOT NULL AUTO_INCREMENT,
slug varchar(80) NOT NULL,
score int(11) unsigned NOT NULL DEFAULT 0,
created_at datetime NOT NULL,
PRIMARY KEY  (id),
KEY slug (slug)
) {$charset_collate};"; return dbDelta( $sql ); }
